import{_ as a,o as s,c as t,a2 as i}from"./chunks/framework.Crpw6aS5.js";const m=JSON.parse('{"title":"Premiers pas","description":"","frontmatter":{},"headers":[],"relativePath":"fr/guide/first-steps.md","filePath":"fr/guide/first-steps.md"}'),r={name:"fr/guide/first-steps.md"};function o(l,e,n,c,u,p){return s(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="premiers-pas" tabindex="-1">Premiers pas <a class="header-anchor" href="#premiers-pas" aria-label="Permalink to &quot;Premiers pas&quot;">​</a></h1><p>Ce guide vous accompagne dans vos premières minutes avec Nid.</p><hr><h2 id="creer-votre-compte" tabindex="-1">Créer votre compte <a class="header-anchor" href="#creer-votre-compte" aria-label="Permalink to &quot;Créer votre compte&quot;">​</a></h2><p>Ouvrez l&#39;application dans votre navigateur (par défaut : <a href="http://localhost:3000" target="_blank" rel="noreferrer">http://localhost:3000</a>).</p><p>Deux options de création de compte s&#39;offrent à vous :</p><h3 id="compte-local" tabindex="-1">Compte local <a class="header-anchor" href="#compte-local" aria-label="Permalink to &quot;Compte local&quot;">​</a></h3><ol><li>Cliquez sur <strong>Créer un compte</strong></li><li>Saisissez votre email et un mot de passe (minimum 8 caractères)</li><li>Cliquez sur <strong>S&#39;inscrire</strong></li></ol><h3 id="connexion-avec-google-sso" tabindex="-1">Connexion avec Google (SSO) <a class="header-anchor" href="#connexion-avec-google-sso" aria-label="Permalink to &quot;Connexion avec Google (SSO)&quot;">​</a></h3><ol><li>Cliquez sur <strong>Se connecter avec Google</strong></li><li>Choisissez votre compte Google</li><li>Autorisez l&#39;accès</li></ol><p>Votre nom et avatar Google sont récupérés automatiquement.</p><blockquote><p>📸 <em>Capture d&#39;écran suggérée : page de login avec les deux options (formulaire + bouton Google SSO)</em></p></blockquote><div class="tip custom-block"><p class="custom-block-title">Fusion de comptes</p><p>Si vous créez d&#39;abord un compte local puis vous connectez avec Google en utilisant le même email, les deux comptes sont automatiquement fusionnés.</p></div><hr><h2 id="devenir-administrateur" tabindex="-1">Devenir administrateur <a class="header-anchor" href="#devenir-administrateur" aria-label="Permalink to &quot;Devenir administrateur&quot;">​</a></h2><p>Le premier utilisateur doit être promu administrateur. Trois options :</p><h3 id="option-a-—-automatiquement-recommande" tabindex="-1">Option A — Automatiquement (recommandé) <a class="header-anchor" href="#option-a-—-automatiquement-recommande" aria-label="Permalink to &quot;Option A — Automatiquement (recommandé)&quot;">​</a></h3><p>Avant de créer votre compte, ajoutez dans le fichier <code>.env</code> :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ADMIN_EMAIL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">votre@email.com</span></span></code></pre></div><p>L&#39;utilisateur qui s&#39;inscrit avec cet email obtient automatiquement le rôle admin.</p><h3 id="option-b-—-en-base-de-donnees" tabindex="-1">Option B — En base de données <a class="header-anchor" href="#option-b-—-en-base-de-donnees" aria-label="Permalink to &quot;Option B — En base de données&quot;">​</a></h3><p>Si votre compte existe déjà :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> postgres</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> psql</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -U</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gmailmanager</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gmailmanager</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;UPDATE users SET role = &#39;admin&#39; WHERE email = &#39;votre@email.com&#39;;&quot;</span></span></code></pre></div><p>Déconnectez-vous puis reconnectez-vous pour que le nouveau rôle prenne effet.</p><h3 id="option-c-—-via-l-interface" tabindex="-1">Option C — Via l&#39;interface <a class="header-anchor" href="#option-c-—-via-l-interface" aria-label="Permalink to &quot;Option C — Via l&#39;interface&quot;">​</a></h3><p>Un administrateur existant peut promouvoir d&#39;autres utilisateurs depuis <strong>Administration</strong> → <strong>Utilisateurs</strong> → <strong>Modifier le rôle</strong>.</p><div class="info custom-block"><p class="custom-block-title">Différence entre les rôles</p><ul><li><strong>Utilisateur</strong> : accès complet à ses propres données (mails, archives, règles, etc.)</li><li><strong>Administrateur</strong> : accès aux données de tous les utilisateurs + gestion des quotas et des rôles</li></ul></div><hr><h2 id="connecter-un-compte-gmail" tabindex="-1">Connecter un compte Gmail <a class="header-anchor" href="#connecter-un-compte-gmail" aria-label="Permalink to &quot;Connecter un compte Gmail&quot;">​</a></h2><p>Une fois connecté, vous devez lier votre boîte Gmail pour que l&#39;application puisse y accéder.</p><ol><li>Rendez-vous dans <strong>Paramètres</strong> (icône ⚙️ dans la sidebar)</li><li>Dans la section <strong>Comptes Gmail</strong>, cliquez sur <strong>Connecter un compte Gmail</strong></li><li>Google vous demande d&#39;autoriser trois types d&#39;accès : <ul><li>Lecture et modification de vos mails</li><li>Gestion de vos labels</li><li>Lecture de votre adresse email</li></ul></li><li>Cliquez sur <strong>Autoriser</strong></li><li>Vous êtes redirigé vers les Paramètres avec une confirmation</li></ol><blockquote><p>📸 <em>Capture d&#39;écran suggérée : page Paramètres avec le bouton &quot;Connecter un compte Gmail&quot; et la liste des comptes connectés</em></p></blockquote><div class="warning custom-block"><p class="custom-block-title">Écran d&#39;avertissement Google</p><p>Si votre projet Google Cloud est en mode &quot;Test&quot;, un écran d&#39;avertissement apparaîtra. Cliquez sur <strong>Paramètres avancés</strong> → <strong>Accéder à nid (non sécurisé)</strong>. C&#39;est normal pour un usage personnel self-hosted.</p></div><h3 id="ajouter-d-autres-comptes-gmail" tabindex="-1">Ajouter d&#39;autres comptes Gmail <a class="header-anchor" href="#ajouter-d-autres-comptes-gmail" aria-label="Permalink to &quot;Ajouter d&#39;autres comptes Gmail&quot;">​</a></h3><p>Répétez l&#39;opération pour connecter d&#39;autres comptes. Vous pouvez gérer jusqu&#39;à 5 comptes par défaut (configurable par l&#39;administrateur).</p><p>Chaque compte apparaît dans le <strong>sélecteur de compte</strong> en haut de la sidebar. Sélectionnez un compte pour afficher ses données dans toutes les sections de l&#39;application.</p><blockquote><p>📸 <em>Capture d&#39;écran suggérée : sélecteur de compte Gmail dans la sidebar avec plusieurs comptes listés</em></p></blockquote><hr><h2 id="decouvrir-le-dashboard" tabindex="-1">Découvrir le Dashboard <a class="header-anchor" href="#decouvrir-le-dashboard" aria-label="Permalink to &quot;Découvrir le Dashboard&quot;">​</a></h2><p>Après avoir connecté votre Gmail, le <strong>Dashboard</strong> charge automatiquement les statistiques de votre boîte :</p><ul><li><strong>Top expéditeurs</strong> : qui vous envoie le plus de mails et occupe le plus d&#39;espace</li><li><strong>Mails les plus volumineux</strong> : identifiez rapidement les mails à supprimer en priorité</li><li><strong>Timeline</strong> : évolution du volume de mails par mois</li><li><strong>Répartition des labels</strong> : distribution de vos labels Gmail</li></ul><blockquote><p>📸 <em>Capture d&#39;écran suggérée : page Dashboard complète avec les 4 graphiques</em></p></blockquote><p>Le chargement initial peut prendre quelques secondes selon la taille de votre boîte.</p><hr><h2 id="votre-premiere-operation-de-nettoyage" tabindex="-1">Votre première opération de nettoyage <a class="header-anchor" href="#votre-premiere-operation-de-nettoyage" aria-label="Permalink to &quot;Votre première opération de nettoyage&quot;">​</a></h2><p>Essayez une première opération de suppression en masse :</p><ol><li>Ouvrez <strong>Mes mails</strong> dans la sidebar</li><li>Utilisez la barre de recherche pour filtrer (ex. : <code>from:newsletter@example.com</code>)</li><li>Cochez la case en tête du tableau pour sélectionner tous les résultats</li><li>Cliquez sur <strong>Supprimer (corbeille)</strong> dans la barre d&#39;actions</li><li>Un <strong>job</strong> est créé — une fenêtre modale affiche la progression en temps réel</li></ol><blockquote><p>📸 <em>Capture d&#39;écran suggérée : page Mes mails avec des mails sélectionnés et la barre d&#39;actions en masse visible</em></p></blockquote><blockquote><p>📸 <em>Capture d&#39;écran suggérée : modale de progression d&#39;un job avec barre de progression</em></p></blockquote><div class="tip custom-block"><p class="custom-block-title">Corbeille vs suppression définitive</p><p>La suppression envoie les mails à la <strong>corbeille Gmail</strong> (récupérables pendant 30 jours). La suppression définitive est irréversible — utilisez-la avec précaution.</p></div><hr><h2 id="votre-premier-archivage" tabindex="-1">Votre premier archivage <a class="header-anchor" href="#votre-premier-archivage" aria-label="Permalink to &quot;Votre premier archivage&quot;">​</a></h2><p>Pour sauvegarder des mails sur votre NAS :</p><ol><li>Dans <strong>Mes mails</strong>, filtrez les mails à archiver</li><li>Sélectionnez-les ou cliquez sur <strong>Tout archiver</strong> pour archiver tous les résultats</li><li>Un job d&#39;archivage est créé</li><li>Les fichiers EML sont sauvegardés dans le dossier d&#39;archives</li></ol><p>Consultez ensuite la section <strong>Archives</strong> pour retrouver vos mails archivés avec la recherche full-text.</p><blockquote><p>📸 <em>Capture d&#39;écran suggérée : section Archives avec la barre de recherche et la liste des mails archivés</em></p></blockquote><hr><h2 id="et-ensuite" tabindex="-1">Et ensuite ? <a class="header-anchor" href="#et-ensuite" aria-label="Permalink to &quot;Et ensuite ?&quot;">​</a></h2><p>Maintenant que vous êtes opérationnel, explorez les autres fonctionnalités :</p><ul><li><a href="./rules.html"><strong>Règles automatiques</strong></a> — automatisez le nettoyage récurrent</li><li><a href="./newsletters.html"><strong>Newsletters</strong></a> — identifiez et nettoyez les newsletters en masse</li><li><a href="./analytics.html"><strong>Analytics</strong></a> — comprenez vos habitudes email</li><li><a href="./settings.html"><strong>Paramètres</strong></a> — activez la 2FA, configurez les webhooks, changez la langue</li></ul>`,60)])])}const h=a(r,[["render",o]]);export{m as __pageData,h as default};
